import asyncio
from aiocoap import *

class CoAPServer():
    def __init__(self):
        self._loop = asyncio.get_event_loop()
        self._resources = {}
        
    def add_resource(self, path, resource):
        self._resources[path] = resource
    
    async def start(self):
        protocol = await Context.create_server_context(self._handle_request, '0.0.0.0', 5683)
        print('Started CoAP server on port 5683')
        
    async def _handle_request(self, request):
        resource = self._resources[request.remote_node.path]
        if request.code == GET:
            return await resource.get()
        elif request.code == PUT:
            await resource.put(request.payload)
    
class TemperatureResource():
    def __init__(self, temp):
        self._temp = temp
        
    async def get(self):
        return Message(code=CONTENT, payload=str(self._temp))
    
    async def put(self, new_temp):
        self._temp = float(new_temp)
        
class LightResource():
    def __init__(self, light):
        self._light = light
        
    async def get(self):
        return Message(code=CONTENT, payload=str(self._light))
    
    async def put(self, new_light):
        self._light = float(new_light)

